#!/usr/bin/env bash
# =============================================================================
# devsetup.sh — Comprehensive Linux Developer Environment Bootstrap
# =============================================================================
# Supports : Debian / Ubuntu (APT) | Arch Linux (Pacman)
# Modes    : --minimal | --full | --devops | --security | --interactive
# Options  : --dry-run | --dotfiles <repo-url>
# Author   : generated by Claude
# Version  : 2.0.0
# =============================================================================

set -euo pipefail
IFS=$'\n\t'

# ─────────────────────────────────────────────────────────────────────────────
# GLOBALS & DEFAULTS
# ─────────────────────────────────────────────────────────────────────────────
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
LOG_FILE="${SCRIPT_DIR}/devsetup.log"
DOTFILES_REPO=""
DRY_RUN=false

# Install flags (all off by default; flags/interactive will enable them)
DO_MINIMAL=false
DO_FULL=false
DO_DEVOPS=false
DO_SECURITY=false
DO_GUI=false
DO_INTERACTIVE=false

REAL_USER="${SUDO_USER:-$USER}"
REAL_HOME="$(eval echo "~${REAL_USER}")"

# ─────────────────────────────────────────────────────────────────────────────
# COLOURS
# ─────────────────────────────────────────────────────────────────────────────
if [[ -t 1 ]]; then
  RED='\033[0;31m';    GREEN='\033[0;32m';  YELLOW='\033[1;33m'
  BLUE='\033[0;34m';   CYAN='\033[0;36m';   BOLD='\033[1m';  RESET='\033[0m'
else
  RED=''; GREEN=''; YELLOW=''; BLUE=''; CYAN=''; BOLD=''; RESET=''
fi

# ─────────────────────────────────────────────────────────────────────────────
# LOGGING HELPERS
# ─────────────────────────────────────────────────────────────────────────────
log()     { echo -e "${GREEN}[✔]${RESET} $*" | tee -a "$LOG_FILE"; }
info()    { echo -e "${BLUE}[➜]${RESET} $*" | tee -a "$LOG_FILE"; }
warn()    { echo -e "${YELLOW}[⚠]${RESET} $*" | tee -a "$LOG_FILE"; }
error()   { echo -e "${RED}[✘]${RESET} $*" | tee -a "$LOG_FILE" >&2; }
section() {
  echo "" | tee -a "$LOG_FILE"
  echo -e "${BOLD}${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${RESET}" | tee -a "$LOG_FILE"
  echo -e "${BOLD}${CYAN}  $*${RESET}" | tee -a "$LOG_FILE"
  echo -e "${BOLD}${CYAN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${RESET}" | tee -a "$LOG_FILE"
}
dry()     { echo -e "${YELLOW}[DRY-RUN]${RESET} Would run: $*" | tee -a "$LOG_FILE"; }

# ─────────────────────────────────────────────────────────────────────────────
# DRY-RUN COMMAND WRAPPER
# ─────────────────────────────────────────────────────────────────────────────
run() {
  if $DRY_RUN; then
    dry "$*"
  else
    "$@" 2>&1 | tee -a "$LOG_FILE" || {
      error "Command failed: $*"
      return 1
    }
  fi
}

# ─────────────────────────────────────────────────────────────────────────────
# ERROR TRAP
# ─────────────────────────────────────────────────────────────────────────────
trap 'error "Unexpected error on line ${LINENO}. Check ${LOG_FILE} for details."; exit 1' ERR

# ─────────────────────────────────────────────────────────────────────────────
# USAGE
# ─────────────────────────────────────────────────────────────────────────────
usage() {
  cat <<EOF
${BOLD}devsetup.sh${RESET} — Linux Developer Environment Bootstrap

${BOLD}USAGE${RESET}
  sudo ./devsetup.sh [MODE] [OPTIONS]

${BOLD}MODES${RESET}
  --minimal       Core packages + languages only
  --full          Everything (languages, tools, shell, GUI, fonts)
  --devops        Core + Docker, Kubernetes, cloud CLIs
  --security      Core + hacking / security toolchain
  --interactive   Prompt for each category interactively

${BOLD}OPTIONS${RESET}
  --dry-run              Print commands without executing
  --dotfiles <repo-url>  Clone and apply your dotfiles repo
  --help                 Show this help message

${BOLD}EXAMPLES${RESET}
  sudo ./devsetup.sh --full
  sudo ./devsetup.sh --minimal --dry-run
  sudo ./devsetup.sh --devops --dotfiles https://github.com/you/dotfiles
  sudo ./devsetup.sh --interactive
EOF
  exit 0
}

# ─────────────────────────────────────────────────────────────────────────────
# ARGUMENT PARSING
# ─────────────────────────────────────────────────────────────────────────────
parse_args() {
  [[ $# -eq 0 ]] && { warn "No mode specified. Run with --help for usage."; DO_INTERACTIVE=true; return; }
  while [[ $# -gt 0 ]]; do
    case "$1" in
      --minimal)     DO_MINIMAL=true ;;
      --full)        DO_FULL=true ;;
      --devops)      DO_DEVOPS=true ;;
      --security)    DO_SECURITY=true ;;
      --interactive) DO_INTERACTIVE=true ;;
      --dry-run)     DRY_RUN=true; warn "DRY-RUN mode enabled — no changes will be made." ;;
      --dotfiles)    shift; DOTFILES_REPO="$1" ;;
      --help|-h)     usage ;;
      *) error "Unknown argument: $1"; usage ;;
    esac
    shift
  done
}

# ─────────────────────────────────────────────────────────────────────────────
# OS DETECTION
# ─────────────────────────────────────────────────────────────────────────────
detect_os() {
  section "Detecting Operating System"

  if [[ -f /etc/os-release ]]; then
    source /etc/os-release
    OS_ID="${ID,,}"       # lowercase
    OS_LIKE="${ID_LIKE,,:-}"
  else
    error "/etc/os-release not found. Cannot detect OS."
    exit 1
  fi

  if [[ "$OS_ID" == "arch" || "$OS_LIKE" == *"arch"* ]]; then
    PKG_MANAGER="pacman"
    PKG_INSTALL="pacman -S --needed --noconfirm"
    PKG_UPDATE="pacman -Syu --noconfirm"
    log "Detected: Arch Linux (pacman)"
  elif [[ "$OS_ID" == "ubuntu" || "$OS_ID" == "debian" || "$OS_LIKE" == *"debian"* || "$OS_LIKE" == *"ubuntu"* ]]; then
    PKG_MANAGER="apt"
    PKG_INSTALL="apt-get install -y"
    PKG_UPDATE="apt-get update && apt-get upgrade -y"
    log "Detected: Debian/Ubuntu (apt)"
  else
    error "Unsupported OS: $OS_ID. Only Arch and Debian/Ubuntu are supported."
    exit 1
  fi

  export PKG_MANAGER PKG_INSTALL PKG_UPDATE OS_ID OS_LIKE
}

# ─────────────────────────────────────────────────────────────────────────────
# ROOT CHECK
# ─────────────────────────────────────────────────────────────────────────────
check_root() {
  if [[ $EUID -ne 0 ]]; then
    error "This script must be run as root (use sudo)."
    exit 1
  fi
  info "Running as root. Real user: ${REAL_USER} (home: ${REAL_HOME})"
}

# ─────────────────────────────────────────────────────────────────────────────
# HELPER: run command as real (non-root) user
# ─────────────────────────────────────────────────────────────────────────────
as_user() {
  if $DRY_RUN; then
    dry "sudo -u ${REAL_USER} $*"
  else
    sudo -u "${REAL_USER}" "$@" 2>&1 | tee -a "$LOG_FILE"
  fi
}

# ─────────────────────────────────────────────────────────────────────────────
# HELPER: check if a command exists
# ─────────────────────────────────────────────────────────────────────────────
has_cmd() { command -v "$1" &>/dev/null; }

# ─────────────────────────────────────────────────────────────────────────────
# HELPER: append line to file if not already present (idempotent)
# ─────────────────────────────────────────────────────────────────────────────
append_if_missing() {
  local line="$1"
  local file="$2"
  if ! grep -qxF "$line" "$file" 2>/dev/null; then
    echo "$line" >> "$file"
  fi
}

# ─────────────────────────────────────────────────────────────────────────────
# INTERACTIVE MODE
# ─────────────────────────────────────────────────────────────────────────────
interactive_mode() {
  section "Interactive Setup"
  echo -e "${BOLD}What would you like to install? (y/n for each)${RESET}\n"

  ask() {
    local prompt="$1"
    local var="$2"
    read -rp "$(echo -e "  ${CYAN}${prompt}${RESET} [y/N] ")" ans
    [[ "${ans,,}" == "y" ]] && eval "$var=true"
  }

  ask "Core tools (git, curl, build tools, neovim, fzf, ripgrep)" "DO_MINIMAL"
  ask "Programming languages (Node, Python, Rust, Go, Java, .NET)" "INSTALL_LANGS"
  ask "DevOps tools (Docker, kubectl, terraform, cloud CLIs)"       "DO_DEVOPS"
  ask "Security / hacking tools (nmap, wireshark, hashcat, gobuster)" "DO_SECURITY"
  ask "Shell setup (zsh + oh-my-zsh + starship)"                   "INSTALL_SHELL"
  ask "CLI enhancements (bat, eza, httpie, tmux)"                   "INSTALL_CLI"
  ask "GUI apps (VS Code, Brave, flameshot, copyq)"                 "DO_GUI"
  ask "Bangla input (ibus-avro)"                                    "INSTALL_IBUS"
  ask "Flatpak + Flathub"                                           "INSTALL_FLATPAK"

  read -rp "$(echo -e "  ${CYAN}Dotfiles repo URL (leave empty to skip):${RESET} ")" DOTFILES_REPO
  export INSTALL_LANGS INSTALL_SHELL INSTALL_CLI INSTALL_IBUS INSTALL_FLATPAK
}

